'use client';

import { cn } from '@/lib/utils';
import { forwardRef, type InputHTMLAttributes } from 'react';

interface InputProps extends InputHTMLAttributes<HTMLInputElement> {
  label?: string;
  error?: string;
}

const Input = forwardRef<HTMLInputElement, InputProps>(({ label, error, className, id, ...props }, ref) => {
  const inputId = id || label?.toLowerCase().replace(/\s/g, '-');
  return (
    <div className="space-y-1.5">
      {label && (
        <label htmlFor={inputId} className="text-[13px] font-medium text-[var(--text-secondary)]">
          {label}
        </label>
      )}
      <input
        ref={ref}
        id={inputId}
        className={cn(
          'w-full px-3 py-2 text-sm rounded-lg border bg-[var(--bg-surface)] text-[var(--text-primary)]',
          'border-[var(--border-default)] focus:outline-2 focus:outline-[var(--accent)] focus:outline-offset-1',
          'placeholder:text-[var(--text-disabled)] transition-all duration-150',
          error && 'border-[var(--error)]',
          className,
        )}
        {...props}
      />
      {error && <p className="text-[12px] text-[var(--error)]">{error}</p>}
    </div>
  );
});

Input.displayName = 'Input';
export default Input;
```

