 5→type Theme = 'light' | 'dark';
 6→
 7→interface ThemeContextValue {
 8→  theme: Theme;
 9→  toggleTheme: () => void;
10→}
11→
12→const ThemeContext = createContext<ThemeContextValue>({
13→  theme: 'light',
14→  toggleTheme: () => {},
15→});
16→
17→const STORAGE_KEY = 'royallazz-theme';
18→
19→function getInitialTheme(): Theme {
20→  if (typeof window === 'undefined') return 'light';
21→  const stored = localStorage.getItem(STORAGE_KEY);
22→  if (stored === 'light' || stored === 'dark') return stored;
23→  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
24→}
25→
26→export function ThemeProvider({ children }: { children: ReactNode }) {
27→  const [theme, setTheme] = useState<Theme>(getInitialTheme);
28→
29→  useEffect(() => {
30→    const root = document.documentElement;
31→    root.classList.toggle('dark', theme === 'dark');
32→    localStorage.setItem(STORAGE_KEY, theme);
33→  }, [theme]);
34→
35→  const toggleTheme = () => setTheme(prev => (prev === 'light' ? 'dark' : 'light'));
36→
37→  return (
38→    <ThemeContext.Provider value={{ theme, toggleTheme }}>
39→      {children}
40→    </ThemeContext.Provider>
41→  );
42→}
43→
44→export function useTheme() {
45→  return useContext(ThemeContext);
46→}
